import json, pandas as pd

path = var_call_QgplrVsNl1j8EpedPvnVaxw2
with open(path,'r') as f:
    recs = json.load(f)

df = pd.DataFrame(recs)

def author_name(a):
    if a is None:
        return None
    if isinstance(a, str):
        s=a.strip()
        if s=='None' or s=='':
            return None
        if s.startswith('{'):
            try:
                j=json.loads(s)
                return j.get('name')
            except Exception:
                return s
        return s
    return str(a)

df['author'] = df['author'].apply(author_name)

lines=[]
for _,r in df.sort_values('title').iterrows():
    t=r['title']
    a=r['author'] if r['author'] else 'Unknown'
    lines.append(f"{t} — {a}")

answer='\n'.join(lines) if lines else 'No matching books found.'
print('__RESULT__:')
print(json.dumps({'answer': answer}))

